@page "/"
@using SkiaSharp

<h2>Hello, world!</h2>
<button @onclick="Create">Create</button>
<p>Status: @msg</p>

@code {
    public string msg = string.Empty;
    void Create()
    {
        try
        {
            SKImageInfo info = new SKImageInfo(612, 792);
            SKSurface surface = SKSurface.Create(info);
            SKCanvas canvas = surface.Canvas;
            SKPaint paint = new SKPaint { TextSize = 11f };
            canvas.DrawText("Hello", 0, 0, paint);
            msg = "End";
        }
        catch (Exception ex)
        {
            msg = ex.ToString();
        }
    }
}
